 };



if (msg.title == "Current Weather Information") {


        var now = new Date();
        var update = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

        // 2. Tradução do ícone atual
        var icone_meteocon = iconMap[msg.payload.icon] || "not-available";

        var payload = {
            "name": msg.payload.location,
            "state": "ES",
            "update": update,
            "data": {
                "temperature": Math.round(msg.payload.tempc),
                "humidity": msg.payload.humidity,
                "detalhe": msg.payload.detail, 
                "temperature_min": Math.round(msg.payload.temp_minc),
                "temperature_max": Math.round(msg.payload.temp_maxc),
                "icon": msg.payload.icon,          // Mantém o original por segurança
                "meteocon": icone_meteocon           // Adiciona o nome para o ícone animado
            }
        };

        flow.set ("f_payload", payload)
        msg.forecast = flow.get("f_forecast") || 0;
        msg.payload = payload;


} else if (msg.title == "5 day Forecast") {
    // 2. Localiza a lista de previsões
    const lista = msg.payload.list || msg.payload;

    if (!Array.isArray(lista)) {
        node.error("Dados não recebidos corretamente. Verifique se o nó está em modo '5-day forecast'.");
        return null;
    }

    // --- SUBSTITUA A SEÇÃO 3 E 4 POR ESTA ---

    // 3. Datas (Hoje e Amanhã) respeitando o fuso horário local
    const agora = new Date();
    const dataHoje = agora.toLocaleDateString('en-CA'); // Gera "2026-01-18"

    const amanha = new Date();
    amanha.setDate(amanha.getDate() + 1);
    const dataAmanha = amanha.toLocaleDateString('en-CA'); // Gera "2026-01-19"

    // Formata dd/mm para exibição na interface
    const todayStr = agora.toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'});
    const nextdayStr = amanha.toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'});

    // 4. Definição dos períodos para buscar (Exatamente como vem no JSON)
    const periodosDesejados = [
        { dia: "hoje", rotulo: "manha", filtro: `${dataHoje} 09:00:00` },
        { dia: "hoje", rotulo: "tarde", filtro: `${dataHoje} 15:00:00` },
        { dia: "hoje", rotulo: "noite", filtro: `${dataHoje} 21:00:00` },
        { dia: "amanha", rotulo: "manha", filtro: `${dataAmanha} 09:00:00` },
        { dia: "amanha", rotulo: "tarde", filtro: `${dataAmanha} 15:00:00` },
        { dia: "amanha", rotulo: "noite", filtro: `${dataAmanha} 21:00:00` }
    ];

    const previsaoFinal = {
        today: {},
        nextday: {},
        today_date: todayStr,    // Variável dd/mm para hoje
        nextday_date: nextdayStr // Variável dd/mm para amanhã
    };

    // 5. Varre a lista e organiza os dados
    periodosDesejados.forEach(p => {
        const dado = lista.find(item => item.dt_txt === p.filtro);
        const destino = (p.dia === "hoje") ? previsaoFinal.today : previsaoFinal.nextday;

        if (dado) {
            const owIcon = dado.weather[0].icon;
            destino[p.rotulo] = {
                hora: dado.dt_txt,
                temp: Math.round(dado.main.temp),
                sensacao: Math.round(dado.main.feels_like),
                clima: dado.weather[0].description,
                icone_ow: owIcon,
                icone_meteocon: iconMap[owIcon] || "not-available"
            };
        } else {
            destino[p.rotulo] = { clima: "Indisp", icone_meteocon: "not-available" };
        }
    });

    // 6. Monta o objeto final e salva no flow
    msg.forecast = previsaoFinal;
    flow.set("f_forecast", msg.forecast);

    // Retorno padrão conforme seu código original
    msg.payload = flow.get("f_payload") || 0;

}

return msg;

